package com.example.kafkademo.model;

public class EventMessage {
    private String eventId;
    private String eventType;
    private String payload;
    private long timestamp;

    public EventMessage() {
    }

    public EventMessage(String eventId, String eventType, String payload, long timestamp) {
        this.eventId = eventId;
        this.eventType = eventType;
        this.payload = payload;
        this.timestamp = timestamp;
    }

    public String getEventId() {
        return eventId;
    }

    public void setEventId(String eventId) {
        this.eventId = eventId;
    }

    public String getEventType() {
        return eventType;
    }

    public void setEventType(String eventType) {
        this.eventType = eventType;
    }

    public String getPayload() {
        return payload;
    }

    public void setPayload(String payload) {
        this.payload = payload;
    }

    public long getTimestamp() {
        return timestamp;
    }

    public void setTimestamp(long timestamp) {
        this.timestamp = timestamp;
    }
}

package com.example.kafkademo.service;

import com.example.kafkademo.config.KafkaConfig;
import com.example.kafkademo.model.EventMessage;
import org.springframework.kafka.core.KafkaTemplate;
import org.springframework.stereotype.Service;

@Service
public class EventProducerService {

    private final KafkaTemplate<String, EventMessage> kafkaTemplate;

    public EventProducerService(KafkaTemplate<String, EventMessage> kafkaTemplate) {
        this.kafkaTemplate = kafkaTemplate;
    }

    public void publishEvent(EventMessage eventMessage) {
        kafkaTemplate.send(KafkaConfig.TOPIC_NAME, eventMessage.getEventId(), eventMessage);
    }
}

package com.example.kafkademo.consumer;

import com.example.kafkademo.config.KafkaConfig;
import com.example.kafkademo.model.EventMessage;
import org.springframework.kafka.annotation.KafkaListener;
import org.springframework.stereotype.Component;

@Component
public class EventConsumer {

    @KafkaListener(topics = KafkaConfig.TOPIC_NAME, groupId = "event-streaming-group")
    public void consume(EventMessage eventMessage) {
        System.out.println("Consumed event: id=" + eventMessage.getEventId()
                + ", type=" + eventMessage.getEventType()
                + ", payload=" + eventMessage.getPayload()
                + ", timestamp=" + eventMessage.getTimestamp());
    }
}

package com.example.kafkademo.controller;

import java.time.Instant;
import java.util.UUID;

import com.example.kafkademo.model.EventMessage;
import com.example.kafkademo.service.EventProducerService;
import org.springframework.http.ResponseEntity;
import org.springframework.web.bind.annotation.*;

@RestController
@RequestMapping("/api/events")
public class EventController {

    private final EventProducerService eventProducerService;

    public EventController(EventProducerService eventProducerService) {
        this.eventProducerService = eventProducerService;
    }

    @PostMapping
    public ResponseEntity<String> publishEvent(@RequestBody EventMessage eventMessage) {
        if (eventMessage.getEventId() == null || eventMessage.getEventId().isBlank()) {
            eventMessage.setEventId(UUID.randomUUID().toString());
        }
        if (eventMessage.getTimestamp() == 0L) {
            eventMessage.setTimestamp(Instant.now().toEpochMilli());
        }
        eventProducerService.publishEvent(eventMessage);
        return ResponseEntity.ok("Event published with id: " + eventMessage.getEventId());
    }
}

